module adder_32bit
(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [31:0] P, G;
wire [31:0] C;

assign P = A[31:0] ^ B[31:0];
assign G = A[31:0] & B[31:0];

wire [15:0] C_first;
assign C_first[0] = G[0] | (P[0] & 1'b0);
assign C_first[1] = G[1] | (P[1] & C_first[0]);
assign C_first[2] = G[2] | (P[2] & C_first[1]);
assign C_first[3] = G[3] | (P[3] & C_first[2]);
assign C_first[4] = G[4] | (P[4] & C_first[3]);
assign C_first[5] = G[5] | (P[5] & C_first[4]);
assign C_first[6] = G[6] | (P[6] & C_first[5]);
assign C_first[7] = G[7] | (P[7] & C_first[6]);
assign C_first[8] = G[8] | (P[8] & C_first[7]);
assign C_first[9] = G[9] | (P[9] & C_first[8]);
assign C_first[10] = G[10] | (P[10] & C_first[9]);
assign C_first[11] = G[11] | (P[11] & C_first[10]);
assign C_first[12] = G[12] | (P[12] & C_first[11]);
assign C_first[13] = G[13] | (P[13] & C_first[12]);
assign C_first[14] = G[14] | (P[14] & C_first[13]);
assign C_first[15] = G[15] | (P[15] & C_first[14]);

wire [15:0] C_second;
assign C_second[0] = G[16] | (P[16] & C_first[15]);
assign C_second[1] = G[17] | (P[17] & C_second[0]);
assign C_second[2] = G[18] | (P[18] & C_second[1]);
assign C_second[3] = G[19] | (P[19] & C_second[2]);
assign C_second[4] = G[20] | (P[20] & C_second[3]);
assign C_second[5] = G[21] | (P[21] & C_second[4]);
assign C_second[6] = G[22] | (P[22] & C_second[5]);
assign C_second[7] = G[23] | (P[23] & C_second[6]);
assign C_second[8] = G[24] | (P[24] & C_second[7]);
assign C_second[9] = G[25] | (P[25] & C_second[8]);
assign C_second[10] = G[26] | (P[26] & C_second[9]);
assign C_second[11] = G[27] | (P[27] & C_second[10]);
assign C_second[12] = G[28] | (P[28] & C_second[11]);
assign C_second[13] = G[29] | (P[29] & C_second[12]);
assign C_second[14] = G[30] | (P[30] & C_second[13]);
assign C_second[15] = G[31] | (P[31] & C_second[14]);

wire C32_temp;
assign C32_temp = G[32] | (P[32] & C_second[15]);

assign S = P ^ {C_second, 1'b0};
assign C32 = C32_temp;

endmodule
